(function(){if(typeof window==='undefined'||typeof document==='undefined'){return;}
var inputEl=document.getElementById('search-input');var statusEl=document.getElementById('search-status');var resultsEl=document.getElementById('search-results');if(!inputEl||!statusEl||!resultsEl){return;}
var state={pages:[],ready:false};function normalizeText(value){return String(value||'').toLowerCase().replace(/[^a-z0-9\s/.-]+/g,' ').replace(/\s+/g,' ').trim();}
function tokenize(query){return normalizeText(query).split(' ').filter(function(token){return token.length>=2;});}
function getQueryFromUrl(){return new URLSearchParams(window.location.search).get('q')||'';}
function updateUrl(query){var nextUrl=query?'?q='+encodeURIComponent(query):window.location.pathname;window.history.replaceState(null,'',nextUrl);}
function clearChildren(node){while(node.firstChild){node.removeChild(node.firstChild);}}
function findMatchIndex(haystack,terms,fallback){var i;for(i=0;i<terms.length;i+=1){var index=haystack.indexOf(terms[i]);if(index!==-1){return index;}}
if(fallback){return haystack.indexOf(fallback);}
return-1;}
function buildSnippet(page,terms,normalizedQuery){var body=String(page.body||'').replace(/\s+/g,' ').trim();if(!body){return'';}
var normalizedBody=normalizeText(body);var startIndex=findMatchIndex(normalizedBody,terms,normalizedQuery);if(startIndex===-1){return body.length>200?body.slice(0,197)+'...':body;}
var snippetStart=Math.max(0,startIndex-50);var snippetEnd=Math.min(body.length,snippetStart+200);var snippet=body.slice(snippetStart,snippetEnd).trim();if(snippetStart>0){snippet='...'+snippet;}
if(snippetEnd<body.length){snippet+='...';}
return snippet;}
function scorePage(page,query,terms){var normalizedQuery=normalizeText(query);var title=normalizeText(page.title);var body=normalizeText(page.body);var url=normalizeText(page.url);var titleWords=title.split(' ').filter(Boolean);var score=0;var matchedTerms=0;if(!normalizedQuery){return null;}
if(title===normalizedQuery){score+=300;}else if(title.indexOf(normalizedQuery)!==-1){score+=160;}
if(url.indexOf(normalizedQuery)!==-1){score+=80;}
terms.forEach(function(term){var termMatched=false;if(title.indexOf(term)!==-1){score+=60;termMatched=true;}
if(url.indexOf(term)!==-1){score+=35;termMatched=true;}
if(body.indexOf(term)!==-1){score+=18;termMatched=true;}
if(titleWords.some(function(word){return word.indexOf(term)===0;})){score+=14;termMatched=true;}
if(termMatched){matchedTerms+=1;}});if(matchedTerms===0){return null;}
if(matchedTerms===terms.length){score+=90;}
if(body.indexOf(normalizedQuery)!==-1){score+=30;}
return{item:page,score:score,snippet:buildSnippet(page,terms,normalizedQuery)};}
function rankResults(query){var terms=tokenize(query);if(terms.length===0){return[];}
return state.pages.map(function(page){return scorePage(page,query,terms);}).filter(Boolean).sort(function(left,right){if(right.score!==left.score){return right.score-left.score;}
return String(left.item.title).localeCompare(String(right.item.title));}).slice(0,20);}
function createResultCard(result){var link=document.createElement('a');var title=document.createElement('h3');var description=document.createElement('p');var url=document.createElement('span');link.className='search-result-card';link.href=result.item.url;title.textContent=result.item.title;description.textContent=result.snippet;url.className='search-result-url';url.textContent=result.item.url;link.appendChild(title);link.appendChild(description);link.appendChild(url);return link;}
function renderNoResults(query){var message=document.createElement('p');var strong=document.createElement('strong');message.className='search-no-results';message.appendChild(document.createTextNode('No results found for "'));strong.textContent=query;message.appendChild(strong);message.appendChild(document.createTextNode('"'));clearChildren(resultsEl);resultsEl.appendChild(message);}
function runSearch(query){var trimmedQuery=String(query||'').trim();if(!state.ready){return;}
clearChildren(resultsEl);if(!trimmedQuery){statusEl.textContent='';return;}
var results=rankResults(trimmedQuery);if(results.length===0){statusEl.textContent='';renderNoResults(trimmedQuery);return;}
statusEl.textContent=results.length+' result'+(results.length===1?'':'s')+' for "'+trimmedQuery+'"';results.forEach(function(result){resultsEl.appendChild(createResultCard(result));});}
function hydrateFromUrl(){var query=getQueryFromUrl();if(!query){return;}
inputEl.value=query;runSearch(query);}
function loadIndex(){fetch('data/search-index.json').then(function(response){if(!response.ok){throw new Error('Search index request failed');}
return response.json();}).then(function(pages){state.pages=Array.isArray(pages)?pages:[];state.ready=true;statusEl.textContent=state.pages.length+' pages indexed and ready to search.';hydrateFromUrl();}).catch(function(){statusEl.textContent='Search index could not be loaded.';});}
inputEl.addEventListener('input',function(event){var query=event.target.value;runSearch(query);updateUrl(query);});window.addEventListener('popstate',function(){var query=getQueryFromUrl();inputEl.value=query;runSearch(query);});loadIndex();})();